template <typename T>
class SharedPtr {
private:
    T* ptr;
    int* count;
public:
    SharedPtr(T* p = nullptr) : ptr(p), count(new int(1)) {}

    ~SharedPtr() {
        (*count)--;
        if (*count == 0) {
            delete ptr;
            delete count;
        }
    }

    SharedPtr(const SharedPtr& sp) {
        ptr = sp.ptr;
        count = sp.count;
        (*count)++;
    }

    SharedPtr& operator=(const SharedPtr& sp) {
        if (this != &sp) {
            if (--(*count) == 0) {
                delete ptr;
                delete count;
            }
            ptr = sp.ptr;
            count = sp.count;
            (*count)++;
        }
        return *this;
    }
    T& operator*() { return *ptr; }
    T* operator->() { return ptr; }
};

